#include <iostream>
#include <vector>
using namespace std;

int main()
{
    int target = 67; // Sabit hedef sayi (demo amacli)

    cout << "Sayi tahmin oyunu basladi! (1-100 arasi)" << endl;
    cout << "(Bu demo, onceden belirlenmis tahminlerle calisir)\n" << endl;

    vector<int> guesses = {50, 75, 62, 68, 65, 67};
    bool found = false;

    for (int guess : guesses)
    {
        cout << "Tahmin: " << guess << endl;

        if (guess == target)
        {
            cout << "Tebrikler! Dogru tahmin: " << target << endl;
            found = true;
            break;
        }
        else if (guess < target)
        {
            cout << "Daha buyuk bir sayi dene.\n" << endl;
        }
        else
        {
            cout << "Daha kucuk bir sayi dene.\n" << endl;
        }
    }

    if (!found)
    {
        cout << "\nTahmin edilemedi. Dogru sayi: " << target << endl;
    }

    cout << "\nToplam deneme sayisi: " << guesses.size() << endl;

    return 0;
}
